const std = @import("std"); const c = @cImport({ @cInclude("unistd.h"); });
fn solveCase(s: []const u8) i32 { var stack: [40010]i32 = undefined; var top: usize = 0; var best: i32 = 0; stack[top] = -1; top += 1; for (s, 0..) |ch, i| { if (ch == '(') { stack[top] = @intCast(i); top += 1; } else { top -= 1; if (top == 0) { stack[top] = @intCast(i); top += 1; } else { const span: i32 = @as(i32, @intCast(i)) - stack[top - 1]; if (span > best) best = span; } } } return best; }
pub fn main() !void { var buf: [1 << 20]u8 = undefined; const read_n = c.read(0, &buf, buf.len); if (read_n <= 0) return; const input = buf[0..@intCast(read_n)]; var lines = std.mem.splitScalar(u8, input, '\n'); const first = lines.next() orelse return; const t = try std.fmt.parseInt(usize, std.mem.trim(u8, first, " \r\t"), 10); var tc: usize = 0; while (tc < t) : (tc += 1) { const n = try std.fmt.parseInt(usize, std.mem.trim(u8, lines.next() orelse "0", " \r\t"), 10); const s = if (n > 0) std.mem.trim(u8, lines.next() orelse "", "\r") else ""; var num_buf: [32]u8 = undefined; const out = try std.fmt.bufPrint(&num_buf, "{d}", .{solveCase(s)}); _ = c.write(1, out.ptr, out.len); if (tc + 1 < t) _ = c.write(1, "\n", 1); } }
